import React from 'react';
function Login() {

    return (
        <div className="login position-absolute top-50 start-50 translate-middle">
            <h1 className="Welcome_text">Welcome back!</h1>
            <div className="login_content p-2">
                <h5 className="Login_text">Email</h5>
                <input className="login_input" type="text" placeholder="Email"/>
            </div>
            <div className="Password_content p-2">
                <p className="Password_text">Password</p>
                <input className="Password_input" type="text" placeholder="Password"/>
            </div>
            <button className="login_btn m-2">Login</button>
        </div>
    );
}

export default Login;
